/**
 * Top-level event firehose, FFI-shaped. Agent streams collapse to a single
 * "agent stream activity" variant — the iOS app doesn't differentiate them
 * at the surface level for v1.
 */

public enum MarmotEventFfi {
    
    case groupJoined(accountIdHex: String, accountLabel: String, groupIdHex: String
    )
    case groupStateUpdated(accountIdHex: String, accountLabel: String, groupIdHex: String
    )
    case messageReceived(received: RuntimeMessageReceivedFfi
    )
    case groupEvent(accountIdHex: String, accountLabel: String
    )
    case accountError(accountIdHex: String, accountLabel: String, message: String
    )
    case agentStreamActivity(accountIdHex: String, accountLabel: String
    )
}


